content:
html, body, * {
    font-family: "JetBrains Mono", "Fira Code", Consolas, "Courier New", monospace;
    color : greenyellow
}

.dark {
    --bg-primary: #000000;
    --bg-secondary: #161616;
    --bg-tertiary: #292929;
    --bg-hover: #1a1a1a;
    --bg-selected: #142744;
    --bg-card: #000000;
    --avatar-bg: #2a2a2a;
    --avatar-text: #9ca3af;
    --border-primary: #2d2d2d;
    --border-secondary: #1f1f1f;
    --border-thread-divider: #383838;
    --text-primary: #5f5f5f;
    --text-secondary: #d4d4d4;
    --text-tertiary: #a1a1aa;
    --text-muted: #8a8a8a;
    --indicator-bg: #121212;
    --indicator-border: #2a2a2a;
    --sidebar-bg: #0a0a0a;
    --sidebar-hover: #0f0f0f;
    --modal-bg: #121212;
    --modal-overlay: rgba(0, 0, 0, 0.85);
    --dropdown-bg: #121212;
    --dropdown-hover: #252525;
    --input-bg: #1a1a1a;
    --input-border: #2a2a2a;
    --color-danger: #ef4444;
    --color-warning: #f59e0b;
    --color-success: #22c55e;
    --color-info: #7289da;
    --background: #09090b;
    --foreground: #fafafa;
    --card: #18181b;
    --card-foreground: #fafafa;
    --popover: #18181b;
    --popover-foreground: #fafafa;
    --primary: #e4e4e7;
    --primary-foreground: #18181b;
    --secondary: #27272a;
    --secondary-foreground: #fafafa;
    --muted: #27272a;
    --muted-foreground: #a1a1aa;
    --accent: #27272a;
    --accent-foreground: #fafafa;
    --destructive: #780000;
    --border: #333333;
    --input: #2a2a2a;
    --ring: #71717a;
    --chart-1: #3b82f6;
    --chart-2: #2dd4bf;
    --chart-3: #f4a261;
    --chart-4: #a855f7;
    --chart-5: #f43f5e;
    --sidebar: #000000;
    --sidebar-foreground: #fafafa;
    --sidebar-primary: #000000;
    --sidebar-primary-foreground: #fafafa;
    --sidebar-accent: #151515;
    --sidebar-accent-foreground: #fafafa;
    --sidebar-border: #333333;
    --sidebar-ring: #71717a;
    --thread-card-bg: #181818;
    --thread-card-bg-hover: #222222;
    --thread-card-border: #2a2a2a;
    --thread-header-bg: #1a1a1a;
    --thread-content-bg: #121212;
}

::-webkit-scrollbar {
  width: 8px;  /* Slimmer width looks better when floating */
  height: 8px; /* For horizontal scrollbars */
}

/* 2. Remove the arrow buttons (triangles) */
::-webkit-scrollbar-button {
  display: none;
  width: 0;
  height: 0;
}
.dark .aster_btn_depth  {
    background-image: none;
    color:white;
    background-color: #222222;

}

/* 3. Make the track entirely invisible */
::-webkit-scrollbar-track {
  background: transparent; 
}

/* 4. The draggable slider */
::-webkit-scrollbar-thumb {
  background-color: #ffffff; 
  border-radius: 10px; /* Fully rounded edges */
}

/* 5. The slider on hover */
::-webkit-scrollbar-thumb:hover {
  background-color: #ffffff; 
}

img[alt="Aster"] {
    filter: hue-rotate(216deg);
}
img[alt="Mail"] {
    filter: hue-rotate(216deg);
}
